"""
orchestrator.py - Pipeline: alle Schritte in Reihenfolge ausfuehren.

Methoden:
  - run_full_pipeline(date) -> Schritte 1-8 in Reihenfolge
  - run_full_pipeline(date, dry_run=True) -> Nur Export + Berechnung, KEINE Buchung/Druck
  - run_reprocess(order_codes) -> Re-Run nur fuer fehlende Orders

Modi:
  --dry-run: Kompletter Ablauf wie Production (Export, Berechnung, Amend-Button,
             Parallelverarbeitung pro Land, Picklisten) — aber OHNE Speichern und OHNE Druck.
             Amendments werden in IDIS-Felder eingetragen aber NICHT gespeichert.
             Jedes Land bekommt einen eigenen Browser-Context (parallel via CDP).
             Ideal fuer Testlaeufe mit dem Kunden.

  --stop-before-save: Schritte 1-4 laufen, Amendments werden in IDIS-Felder
             eingetragen aber NICHT gespeichert. Pipeline stoppt nach Schritt 4.
             Benutzer kann Zahlen am Bildschirm pruefen, bevor manuell
             gespeichert wird. Schritte 5-8 werden NICHT ausgefuehrt.

Fehlerbehandlung:
  - Fehlende Masterdaten -> Skip + Fehlerliste, Rest normal weiter
  - Plausibilitaet fehlgeschlagen -> KEIN Druck
  - 0 Export-Zeilen -> Retry-Logik (konfigurierbar, default 3x20min)
"""

import asyncio
import json
import logging
import os
import sys
import traceback
from datetime import date, datetime
from pathlib import Path
from urllib.request import Request, urlopen
from urllib.error import URLError

from daily_report import DailyReport
from nacke_email import send_start_email, send_end_email
from master_data import MasterData
from overconfirmation import OverconfirmationCalculator
try:
    from picklist_generator import PicklistGenerator
    PICKLIST_AVAILABLE = True
except (ImportError, SyntaxError) as e:
    logging.getLogger(__name__).warning("Picklist-Modul nicht verfuegbar: %s - Picklisten werden uebersprungen", e)
    PicklistGenerator = None
    PICKLIST_AVAILABLE = False
try:
    from printer import Printer
    PRINTER_AVAILABLE = True
except (ImportError, SyntaxError) as e:
    logging.getLogger(__name__).warning("Printer-Modul nicht verfuegbar: %s - Druck wird uebersprungen", e)
    Printer = None
    PRINTER_AVAILABLE = False
try:
    import generate_todo_list
    TODO_LIST_AVAILABLE = True
except (ImportError, SyntaxError) as e:
    logging.getLogger(__name__).warning("ToDo-Modul nicht verfuegbar: %s - ToDo-Liste wird uebersprungen", e)
    generate_todo_list = None
    TODO_LIST_AVAILABLE = False

logger = logging.getLogger(__name__)


class Orchestrator:
    """Zentrale Pipeline-Steuerung."""

    # CDP-Ports pro Land (kein Sharing, jedes Land eigener Chrome-Prozess)
    COUNTRY_PORTS = {"A": 9223, "CH": 9224, "E": 9225, "SK": 9226, "OL": 9227}

    def __init__(self, config_path: str = "config.json"):
        self.config_path = config_path
        with open(config_path, "r", encoding="utf-8") as f:
            self.cfg = json.load(f)

        # Reporting-Konfiguration
        reporting = self.cfg.get("reporting", {})
        self._report_url = reporting.get("edge_function_url", "")
        self._machine_name = reporting.get("machine_name", "nacke-vm")
        self._reporting_enabled = reporting.get("enabled", False)
        self._machine_token = os.getenv("MACHINE_TOKEN", "")
        # Fallback: .env Datei lesen wenn Env-Variable nicht gesetzt
        if not self._machine_token:
            env_path = Path(__file__).parent / ".env"
            if env_path.exists():
                for line in env_path.read_text(encoding="utf-8").splitlines():
                    if line.strip().startswith("MACHINE_TOKEN="):
                        self._machine_token = line.split("=", 1)[1].strip()
                        logger.info("MACHINE_TOKEN aus .env geladen")
                        break

        # Workflow-Monitor Logging
        self._workflow_log_url = reporting.get(
            "workflow_log_url",
            "https://crslpxgwxjmovrhyxiim.supabase.co/functions/v1/pipeline-monitor?action=log",
        )
        self._workflow_run_id = None  # wird bei Start gesetzt

        # FIX: Retry-Konfiguration
        schedule = self.cfg.get("schedule", {})
        self._retry_count = schedule.get("retry_count", 3)
        self._retry_delay_minutes = schedule.get("retry_delay_minutes", 20)

    def _log_workflow(self, event: str, **kwargs) -> None:
        """Sendet Start/Step/Finish an workflow_runs via pipeline-monitor."""
        try:
            payload = {"workflow_id": "nacke", "event": event}
            if self._workflow_run_id:
                payload["run_id"] = self._workflow_run_id
            payload.update(kwargs)

            body = json.dumps(payload, default=str).encode("utf-8")
            req = Request(
                self._workflow_log_url,
                data=body,
                headers={"Content-Type": "application/json"},
                method="POST",
            )
            with urlopen(req, timeout=10) as resp:
                if resp.status < 300:
                    resp_data = json.loads(resp.read().decode("utf-8"))
                    if event == "start" and resp_data.get("run_id"):
                        self._workflow_run_id = resp_data["run_id"]
                        logger.info("Workflow-Log gestartet: %s", self._workflow_run_id)
                    else:
                        logger.info("Workflow-Log: %s", event)
        except Exception as e:
            logger.warning("Workflow-Log fehlgeschlagen (unkritisch): %s", e)

    def _send_report(self, result: dict, run_date: date) -> None:
        """Sendet Pipeline-Ergebnis an Supabase Edge Function + Email."""
        # Workflow-Monitor: Finish loggen (immer, unabhaengig von Reporting)
        if self._workflow_run_id:
            wf_metrics = {
                "duration_s": int(result.get("duration_seconds", 0)),
                "amendments": result.get("steps", {}).get(
                    "overconfirmation", {}
                ).get("amendments_applied", result.get("steps", {}).get(
                    "overconfirmation", {}
                ).get("amendments_calculated", 0)),
                "orders_checked": result.get("steps", {}).get(
                    "export_pre", {}
                ).get("rows", 0),
                "mode": result.get("mode", "unknown"),
            }
            # Amendment-Details fuer Dashboard (Order-ID, Land, alt/neu)
            amendments_raw = result.get("_amendments", [])
            step_log = [
                {
                    "order_id": a.get("order_id", a.get("aros_key", "")),
                    "land": a.get("land", ""),
                    "alt_menge": a.get("alt_menge", 0),
                    "neu_menge": a.get("neu_menge", 0),
                }
                for a in amendments_raw
            ]
            self._log_workflow(
                "finish",
                step_current="send-report" if result.get("status") != "error" else "error",
                metrics=wf_metrics,
                error_message=result.get("error"),
                step_log=step_log,
            )

        if not self._reporting_enabled or not self._report_url:
            return
        if not self._machine_token:
            logger.warning("MACHINE_TOKEN nicht gesetzt - Report uebersprungen")
            return

        try:
            report_data = {
                "date": str(run_date),
                "mode": result.get("mode", "unknown"),
                "dry_run": result.get("mode") == "dry_run",
                "status": result.get("status", "unknown"),
                "duration_seconds": result.get("duration_seconds", 0),
                "steps": result.get("steps", {}),
                "errors": [result["error"]] if result.get("error") else [],
                "total_errors": 1 if result.get("error") else 0,
                "total_amended": result.get("steps", {}).get(
                    "overconfirmation", {}
                ).get("amendments_calculated", 0),
            }

            # HTML-Report fuer Email generieren (ausgelagert nach daily_report.py)
            html_report = None  # TODO: DailyReport.build_html_report existiert nicht, Email geht via send_end_email

            report_payload = {
                "machine_token": self._machine_token,
                "report": report_data,
                "html_report": html_report,
                "send_always": True,
            }

            body = json.dumps(report_payload, default=str).encode("utf-8")
            req = Request(
                self._report_url,
                data=body,
                headers={"Content-Type": "application/json"},
                method="POST",
            )
            with urlopen(req, timeout=30) as resp:
                if resp.status < 300:
                    resp_body = resp.read().decode("utf-8", errors="replace")
                    logger.info("Report gesendet (Status %d): %s", resp.status, resp_body[:200])
                else:
                    logger.warning("Report-Antwort: %d", resp.status)

        except (URLError, OSError) as e:
            logger.warning("Report senden fehlgeschlagen: %s", e)
        except Exception as e:
            logger.warning("Report-Fehler (unkritisch): %s", e)

    def run_full_pipeline(
        self,
        run_date: date | None = None,
        dry_run: bool = False,
        stop_before_save: bool = False,
    ) -> dict:
        """Fuehrt die Pipeline aus."""
        if run_date is None:
            run_date = date.today()

        if stop_before_save and dry_run:
            raise ValueError(
                "--stop-before-save und --dry-run sind nicht kombinierbar. "
                "stop-before-save fuellt Felder im Browser, dry-run oeffnet keinen Browser."
            )

        start_time = datetime.now()
        if stop_before_save:
            mode = "stop-before-save"
        elif dry_run:
            mode = "dry-run"
        else:
            mode = "production"
        result = {
            "date": str(run_date),
            "mode": mode,
            "status": "pending",
            "steps": {},
        }

        # Workflow-Monitor: Start loggen
        self._log_workflow("start", trigger="scheduler", vm=self._machine_name)

        logger.info("=" * 60)
        logger.info("PIPELINE START: %s [%s]", run_date, mode.upper())
        if dry_run:
            logger.info("DRY-RUN: Keine Buchungen in IDIS, kein Druck")
        if stop_before_save:
            logger.info(
                "STOP-BEFORE-SAVE: Felder werden ausgefuellt, "
                "NICHT gespeichert. Pipeline stoppt nach Schritt 4."
            )
        logger.info("=" * 60)

        # Start-Email senden (test_mode=True = nur Bodo)
        try:
            send_start_email(mode, test_mode=False)
        except Exception as e:
            logger.warning("Start-Email fehlgeschlagen (unkritisch): %s", e)

        try:
            # Packaging-Mismatches + Missing Weights von vorherigem Run loeschen
            for cleanup_file in ["logs/packaging_mismatches.json", "logs/missing_weights.json"]:
                p = Path(cleanup_file)
                if p.exists():
                    p.unlink()

            # --- Schritt 1: Masterdatei laden ---
            logger.info("--- Schritt 1: Masterdatei laden ---")
            master = MasterData(self.config_path)
            result["steps"]["master_data"] = {
                "orders": len(master._orders),
                "ol_kartonage": len(master._ol_kartonage),
            }

            # --- Schritte 2-5: IDIS ---
            pre_export_rows, amendments, post_export_rows = asyncio.run(
                self._run_idis_steps(
                    master, run_date,
                    dry_run=dry_run,
                    stop_before_save=stop_before_save,
                )
            )

            # FIX: Sauberer Exit bei 0 Zeilen nach Retries
            if not pre_export_rows and not amendments:
                result["steps"]["export_pre"] = {"rows": 0}
                result["steps"]["overconfirmation"] = {"amendments_calculated": 0}
                result["status"] = "no_orders"
                result["error"] = (
                    "Keine Orders fuer %s nach %d Versuchen. "
                    "Moeglicherweise Year-End Processing oder keine Abrufe."
                    % (run_date, self._retry_count + 1)
                )
                logger.warning(result["error"])
                result["duration_seconds"] = (datetime.now() - start_time).total_seconds()
                self._send_report(result, run_date)
                try:
                    send_end_email(result, test_mode=False)
                except Exception as e:
                    logger.warning("End-Email fehlgeschlagen (unkritisch): %s", e)
                return result

            result["steps"]["export_pre"] = {"rows": len(pre_export_rows)}
            result["steps"]["overconfirmation"] = {
                "amendments_calculated": len(amendments),
                "amendments_applied": 0 if (dry_run or stop_before_save) else len(amendments),
            }
            # Amendments fuer HTML-Report speichern (alle Modi)
            result["_amendments"] = amendments
            if dry_run and amendments:
                result["steps"]["overconfirmation"]["would_amend"] = [
                    {
                        "order_id": a.get("order_id", ""),
                        "alt_menge": a.get("alt_menge", 0),
                        "neu_menge": a.get("neu_menge", 0),
                    }
                    for a in amendments[:20]
                ]
                if len(amendments) > 20:
                    result["steps"]["overconfirmation"]["would_amend_total"] = len(amendments)

            # --- STOP-BEFORE-SAVE: Pipeline hier anhalten ---
            if stop_before_save:
                logger.info("=" * 60)
                logger.info("STOPPED BEFORE SAVE - Verify manually")
                logger.info("=" * 60)
                logger.info(
                    "Amendments wurden in IDIS-Felder eingetragen "
                    "aber NICHT gespeichert."
                )
                logger.info(
                    "Bitte Zahlen am Bildschirm pruefen. "
                    "Schritte 5-8 werden NICHT ausgefuehrt."
                )
                if amendments:
                    logger.info("--- Zusammenfassung: Was gespeichert WUERDE ---")
                    for a in amendments:
                        logger.info(
                            "  Order %-25s  alt: %6s  -> neu: %6s",
                            a.get("order_id", "?"),
                            a.get("alt_menge", "?"),
                            a.get("neu_menge", "?"),
                        )
                    logger.info("Gesamt: %d Amendments", len(amendments))
                else:
                    logger.info("Keine Amendments berechnet - nichts zu pruefen.")

                result["steps"]["overconfirmation"]["filled_not_saved"] = len(amendments)
                result["steps"]["overconfirmation"]["would_save"] = [
                    {
                        "order_id": a.get("order_id", ""),
                        "alt_menge": a.get("alt_menge", 0),
                        "neu_menge": a.get("neu_menge", 0),
                    }
                    for a in amendments
                ]
                result["steps"]["export_post"] = {"skipped": True, "reason": "stop-before-save"}
                result["steps"]["picklists"] = {"skipped": True, "reason": "stop-before-save"}
                result["steps"]["report"] = {"skipped": True, "reason": "stop-before-save"}
                result["steps"]["print"] = {"skipped": True, "reason": "stop-before-save"}
                result["status"] = "stopped_before_save"

                result["duration_seconds"] = (datetime.now() - start_time).total_seconds()
                self._send_report(result, run_date)
                return result

            result["steps"]["export_post"] = {
                "rows": len(post_export_rows),
            }

            # --- Schritt 6: Picklisten generieren ---
            if not PICKLIST_AVAILABLE:
                logger.warning("--- Schritt 6: UEBERSPRUNGEN (Picklist-Modul nicht verfuegbar) ---")
                generated = []
                missing_keys = []
                result["steps"]["picklists"] = {"skipped": True, "reason": "picklist_unavailable"}
            else:
                logger.info("--- Schritt 6: Picklisten generieren ---")
                aros_keys = list(set(
                    str(r.get("aros_key", "")) for r in post_export_rows if r.get("aros_key")
                ))
                valid_keys, missing_keys = master.validate_orders(aros_keys)
                valid_keys_set = set(valid_keys)

                valid_rows = [
                    r for r in post_export_rows
                    if str(r.get("aros_key", "")) in valid_keys_set
                ]

                gen = PicklistGenerator(master, self.config_path)
                generated = gen.generate(valid_rows, run_date)
                result["steps"]["picklists"] = {
                    "generated": len(generated),
                    "skipped_missing": len(missing_keys),
                    "missing_keys": missing_keys,
                }


# --- Schritt 7: Tagesbericht ---
            logger.info("--- Schritt 7: Tagesbericht ---")
            end_time = datetime.now()
            report = DailyReport(self.config_path)
            plausibility_ok, report_path = report.generate_report(
                run_date=run_date,
                start_time=start_time,
                end_time=end_time,
                export_rows=post_export_rows,
                generated_lists=generated,
                missing_keys=missing_keys,
                amendments=amendments,
            )
            result["steps"]["report"] = {
                "path": report_path,
                "plausibility_ok": plausibility_ok,
            }

            # --- Schritt 8: Druck ---
            if dry_run:
                logger.info("--- Schritt 8: DRUCK UEBERSPRUNGEN (Dry-Run) ---")
                result["steps"]["print"] = {"skipped": True, "reason": "dry-run"}
            elif not generated:
                logger.warning("--- Schritt 8: DRUCK UEBERSPRUNGEN (keine Picklisten erstellt) ---")
                result["steps"]["print"] = {"skipped": True, "reason": "no_picklists"}
            elif not PRINTER_AVAILABLE:
                logger.warning("--- Schritt 8: DRUCK UEBERSPRUNGEN (Printer-Modul nicht verfuegbar) ---")
                result["steps"]["print"] = {"skipped": True, "reason": "printer_unavailable"}
            else:
                logger.info("--- Schritt 8: Druck (%d Picklisten) ---", len(generated))
                printer = Printer(self.config_path)
                print_result = printer.print_all(generated)
                result["steps"]["print"] = print_result

            # --- Schritt 9: ToDo-Liste generieren (nicht kritisch) ---
            if not TODO_LIST_AVAILABLE:
                logger.warning("--- Schritt 9: ToDo-LISTE UEBERSPRUNGEN (Modul nicht verfuegbar) ---")
                result["steps"]["todo_list"] = {"skipped": True, "reason": "module_unavailable"}
            else:
                try:
                    logger.info("--- Schritt 9: ToDo-Liste generieren ---")
                    todo_csv = generate_todo_list.find_latest_post_export(
                        generate_todo_list.EXPORT_DIR, run_date
                    )
                    if not todo_csv or not todo_csv.exists():
                        logger.warning("ToDo-Liste: keine Post-Export CSV gefunden")
                        result["steps"]["todo_list"] = {"skipped": True, "reason": "no_csv"}
                    else:
                        todo_orders = generate_todo_list.read_post_export(todo_csv)
                        todo_master = generate_todo_list.read_masterdatei(
                            generate_todo_list.MASTER_PATH
                        )
                        todo_picklist_map = generate_todo_list.scan_picklists(
                            generate_todo_list.PICKLIST_DIR, run_date
                        )
                        todo_output = generate_todo_list.OUTPUT_DIR / f"ToDo_{run_date.strftime('%Y-%m-%d')}.xlsx"
                        todo_total, todo_no_master, todo_no_list = generate_todo_list.generate_todo_xlsx(
                            todo_orders, todo_master, todo_picklist_map, todo_output, run_date
                        )
                        result["steps"]["todo_list"] = {
                            "generated": True,
                            "total_orders": todo_total,
                            "missing_master": todo_no_master,
                            "missing_list": todo_no_list,
                            "output": str(todo_output),
                        }
                        logger.info("ToDo-Liste erstellt: %d Orders", todo_total)
                except Exception as e:
                    logger.error(
                        "Schritt 9 FEHLGESCHLAGEN (nicht kritisch, Pipeline laeuft weiter): %s",
                        e, exc_info=True,
                    )
                    result["steps"]["todo_list"] = {"error": str(e), "status": "failed"}

            result["status"] = "completed"
            logger.info("PIPELINE ABGESCHLOSSEN: %s [%s]", result["status"], mode)

        except Exception as e:
            logger.error("PIPELINE FEHLER: %s", e, exc_info=True)
            result["status"] = "error"
            result["error"] = str(e)
            result["traceback"] = traceback.format_exc()

        result["duration_seconds"] = (datetime.now() - start_time).total_seconds()
        self._send_report(result, run_date)

        try:
            send_end_email(result, test_mode=False)
        except Exception as e:
            logger.warning("End-Email fehlgeschlagen (unkritisch): %s", e)

        return result

    # ------------------------------------------------------------------
    # IDIS-Schritte (Pre/Post-Export: Haupt-Browser, Amendments: parallel)
    # ------------------------------------------------------------------

    async def _run_idis_steps(
        self,
        master: MasterData,
        run_date: date,
        dry_run: bool = False,
        stop_before_save: bool = False,
    ) -> tuple[list[dict], list[dict], list[dict]]:
        """Schritte 2-5: Pre-Export, Overconfirmation, Amendments, Post-Export.

        Ablauf (v5.2 — Parallelverarbeitung):
        - Schritt 2: Haupt-Browser → Login + Pre-Export (alle Orders)
        - Schritt 3: Overconfirmation berechnen (synchron)
        - Schritt 4: Amendments PARALLEL pro Land (je ein Browser-Context)
        - Schritt 5: Haupt-Browser → Post-Export (alle Orders)

        Ausnahme: stop_before_save bleibt sequentiell (Browser offen zur Verifikation).
        Retry-Logik bei 0 Export-Zeilen (z.B. Year-End Processing, spaete Abrufe).
        """
        from idis_browser import IdisBrowser

        browser = IdisBrowser(self.config_path)
        close_browser = not stop_before_save
        try:
            # Schritt 2: Login + Pre-Export
            logger.info("--- Schritt 2: IDIS Login + Export (Pre-Over) ---")
            await browser.login()
            _, pre_export_rows = await browser.export_orders(run_date, "pre")
            logger.info("Pre-Export: %d Zeilen", len(pre_export_rows))

            # FIX: Retry-Logik bei 0 Zeilen (nicht im dry_run)
            if not pre_export_rows and not dry_run:
                retry_count = self._retry_count
                retry_delay = self._retry_delay_minutes

                for attempt in range(1, retry_count + 1):
                    logger.warning(
                        "0 Zeilen im Export (Versuch %d/%d). "
                        "Warte %d Minuten vor erneutem Versuch...",
                        attempt, retry_count, retry_delay,
                    )
                    await asyncio.sleep(retry_delay * 60)

                    # Zurueck zum Main Menu und erneut exportieren
                    try:
                        await browser.navigate_to_main_menu()
                    except Exception as nav_err:
                        logger.warning(
                            "Navigation zum Main Menu fehlgeschlagen: %s - versuche Re-Login",
                            nav_err,
                        )
                        try:
                            await browser.close()
                        except Exception as e:
                            logger.warning("Browser-Close bei Retry fehlgeschlagen: %s", e)
                        browser = IdisBrowser(self.config_path)
                        await browser.login()

                    _, pre_export_rows = await browser.export_orders(run_date, "pre")
                    logger.info(
                        "Retry %d/%d: %d Zeilen",
                        attempt, retry_count, len(pre_export_rows),
                    )

                    if pre_export_rows:
                        break

                if not pre_export_rows:
                    logger.warning(
                        "Nach %d Retries immer noch 0 Zeilen. Pipeline beendet.",
                        retry_count,
                    )
                    return [], [], []

            # Bei dry_run und 0 Zeilen: sofort return (kein Retry noetig)
            if not pre_export_rows:
                logger.info("Keine Orders fuer %s - Pipeline beendet (0 Zeilen).", run_date)
                return [], [], []

            # Schritt 3: Overconfirmation berechnen (synchron)
            logger.info("--- Schritt 3: Overconfirmation berechnen ---")
            calc = OverconfirmationCalculator(master, self.config_path)
            amendments = calc.calculate_amendments(pre_export_rows)
            logger.info("Amendments berechnet: %d", len(amendments))

            # ----------------------------------------------------------
            # Schritt 4: Amendments anwenden
            # stop_before_save: sequentiell (Browser bleibt offen)
            # dry_run + production: PARALLEL pro Land
            # ----------------------------------------------------------
            if stop_before_save:
                if amendments:
                    logger.info(
                        "--- Schritt 4: Amendments in IDIS eintragen "
                        "(OHNE Speichern, sequentiell) ---"
                    )
                    filled = await browser.apply_amendments(
                        amendments, stop_before_save=True
                    )
                    logger.info(
                        "Amendments eingetragen (nicht gespeichert): %d/%d",
                        filled, len(amendments),
                    )
                else:
                    logger.info("--- Schritt 4: Keine Amendments noetig ---")

                logger.info(
                    "--- Schritt 5: UEBERSPRUNGEN (stop-before-save) ---"
                )
                return pre_export_rows, amendments, pre_export_rows
            elif amendments:
                if dry_run:
                    logger.info(
                        "--- Schritt 4: Amendments PARALLEL eintragen "
                        "(Dry-Run, OHNE Speichern) ---"
                    )
                else:
                    logger.info(
                        "--- Schritt 4: Amendments PARALLEL anwenden ---"
                    )
                total_applied = await self._apply_amendments_parallel(
                    amendments, run_date, stop_before_save=dry_run,
                )
                logger.info(
                    "Amendments %s: %d/%d",
                    "eingetragen (nicht gespeichert)" if dry_run else "angewendet",
                    total_applied, len(amendments),
                )
            else:
                logger.info("--- Schritt 4: Keine Amendments noetig ---")

                # Dry-Run: Browser-Konnektivitaet pro Land verifizieren
                if dry_run:
                    await self._verify_country_browsers(run_date)

            # Schritt 5: Post-Export
            logger.info("--- Schritt 5: IDIS Export (Post-Over) ---")
            _, post_export_rows = await browser.export_orders(run_date, "post")
            logger.info("Post-Export: %d Zeilen", len(post_export_rows))

            return pre_export_rows, amendments, post_export_rows
        finally:
            if close_browser:
                await browser.close()
            else:
                logger.info(
                    "Browser bleibt OFFEN fuer manuelle Verifikation. "
                    "Bitte nach Pruefung manuell schliessen."
                )

    # ------------------------------------------------------------------
    # Browser-Verifizierung pro Land (Dry-Run)
    # ------------------------------------------------------------------

    async def _verify_country_browsers(self, run_date: date) -> dict:
        """Verifiziert Browser-Konnektivitaet pro Overconfirmation-Land (PARALLEL).

        Wird im Dry-Run aufgerufen wenn 0 Amendments vorliegen, um sicherzustellen
        dass die parallelen Browser-Sessions am naechsten Production-Tag funktionieren.

        Pro Land (parallel): Browser spawnen -> Login -> Date Filter ->
        Company Filter setzen -> Show Result -> Row Count pruefen -> Close.
        Schreibt NICHTS in IDIS.

        Returns:
            Dict mit {country: {"ok": bool, "rows": int, "error": str|None}}
        """
        from idis_browser import IdisBrowser

        verify_countries = self.cfg.get(
            "verify_browsers_countries", ["A", "CH", "E", "SK", "OL"]
        )

        parallel_cfg = self.cfg.get("parallel", {})
        max_parallel = parallel_cfg.get("max_countries", 4)
        semaphore = asyncio.Semaphore(max_parallel)

        logger.info(
            "=== BROWSER-VERIFIZIERUNG (PARALLEL): %d Laender (%s), max %d gleichzeitig ===",
            len(verify_countries), ", ".join(verify_countries), max_parallel,
        )

        self._log_workflow(
            "step",
            step_current="verify-browsers",
            countries=verify_countries,
        )

        # Mapping: Kurzcode -> Suchtext im Dropdown (IDIS zeigt "C & A ...")
        COUNTRY_SEARCH = {
            "A": "Austria",
            "CH": "Switzerland",
            "E": "Spain",
            "SK": "Slovakia",
            "OL": "Online",
            "NL": "Netherlands",
            "D": "Germany",
            "B": "Belgium",
            "F": "France",
            "TR": "Turkey",
        }

        async def _verify_single_country(country: str) -> tuple:
            """Verifiziert einen einzelnen Laender-Browser."""
            async with semaphore:
                country_browser = IdisBrowser(self.config_path)
                country_browser._country_label = country
                # FIX: Eigener CDP-Port pro Land (kein Sharing)
                port = self.COUNTRY_PORTS.get(country, 9228)
                country_browser._conn._port = port
                country_browser._conn._cdp_url = f"http://127.0.0.1:{port}"
                try:
                    logger.info("[%s] Browser-Verifizierung starten...", country)

                    # Login (eigene Session)
                    await country_browser.login()
                    logger.info("[%s] Login OK", country)

                    # Navigate to Process AROS
                    await country_browser.navigate_to_process_aros()
                    logger.info("[%s] Process AROS erreicht", country)

                    page = country_browser._page

                    # Date Filter setzen
                    date_str = run_date.strftime("%d.%m.%Y")
                    date_select = page.locator(IdisBrowser.SEL_FILTER_IMPORT_DATE)
                    options = await date_select.locator("option").all()
                    for opt in options:
                        val = await opt.get_attribute("value") or ""
                        txt = (await opt.inner_text()).strip()
                        if date_str in val or date_str in txt:
                            await date_select.select_option(value=val)
                            logger.info("[%s] Date Filter: %s", country, val)
                            break

                    # Company Filter setzen (Land)
                    # IDIS Dropdown zeigt "C & A Austria", "C & A Switzerland" etc.
                    # Matching per Laendername im Text (nicht per Kurzcode)
                    search_name = COUNTRY_SEARCH.get(country.upper(), country)
                    company_select = page.locator(IdisBrowser.SEL_FILTER_COMPANY)
                    company_options = await company_select.locator("option").all()
                    company_found = False
                    for opt in company_options:
                        val = await opt.get_attribute("value") or ""
                        txt = (await opt.inner_text()).strip()
                        if search_name.upper() in txt.upper():
                            await company_select.select_option(value=val)
                            logger.info("[%s] Company Filter: %s (val=%s)", country, txt, val)
                            company_found = True
                            break

                    if not company_found:
                        logger.warning(
                            "[%s] Company Filter nicht gefunden (gesucht: %s) — verfuegbar: %s",
                            country, search_name,
                            ", ".join([
                                (await o.inner_text()).strip()
                                for o in company_options[:20]
                            ]),
                        )

                    # Show Result klicken
                    await page.click(IdisBrowser.SEL_SHOW_RESULT)
                    # DISABLED: await page.wait_for_load_state("domcontentloaded")
                    await page.wait_for_timeout(3000)

                    # Zeilen zaehlen
                    data_rows = page.locator("tr.row_odd, tr.row_even")
                    row_count = await data_rows.count()
                    logger.info(
                        "[%s] Result-Tabelle: %d Zeilen -> %s",
                        country, row_count,
                        "Orders vorhanden" if row_count > 0 else "Keine Orders (OK fuer Verifizierung)",
                    )

                    return country, {"ok": True, "rows": row_count, "error": None}

                except Exception as e:
                    logger.error(
                        "[%s] Browser-Verifizierung FEHLGESCHLAGEN: %s",
                        country, e, exc_info=True,
                    )
                    return country, {"ok": False, "rows": 0, "error": str(e)}
                finally:
                    # NUR Playwright stoppen, Context NICHT schliessen!
                    # Grund: Alle Browser teilen sich Chrome via CDP Port 9222.
                    # context.close() kann den Haupt-Browser-Context invalidieren
                    # und den Post-Export crashen lassen.
                    try:
                        if hasattr(country_browser, "_pw") and country_browser._pw:
                            await country_browser._pw.stop()
                            country_browser._pw = None
                        logger.info("[%s] Playwright getrennt", country)
                    except Exception as e:
                        logger.warning('Playwright cleanup: %s', e)

        # Alle Laender PARALLEL ausfuehren
        raw_results = await asyncio.gather(
            *[_verify_single_country(c) for c in verify_countries],
            return_exceptions=True,
        )

        results = {}
        for item in raw_results:
            if isinstance(item, Exception):
                logger.error("Unerwarteter Fehler bei Verifizierung: %s", item)
            else:
                country, data = item
                results[country] = data

        # Zusammenfassung
        ok_count = sum(1 for r in results.values() if r["ok"])
        fail_count = len(results) - ok_count
        total_rows = sum(r["rows"] for r in results.values())

        logger.info(
            "=== BROWSER-VERIFIZIERUNG ABGESCHLOSSEN: %d/%d OK, %d Zeilen gesamt ===",
            ok_count, len(results), total_rows,
        )

        if fail_count > 0:
            failed = [c for c, r in results.items() if not r["ok"]]
            logger.warning(
                "WARNUNG: Browser-Verifizierung fehlgeschlagen fuer: %s",
                ", ".join(failed),
            )

        return results

    # ------------------------------------------------------------------
    # Parallelverarbeitung pro Land
    # ------------------------------------------------------------------

    async def _apply_amendments_parallel(
        self,
        amendments: list[dict],
        run_date: date,
        stop_before_save: bool = False,
    ) -> int:
        """Wendet Amendments parallel pro Land an (v5.2).

        Pro Land wird eine eigene Playwright-Browser-Instanz (Context) gestartet.
        Alle Instanzen teilen sich den Chrome-Prozess via CDP Port 9222.
        Jeder Context hat eine isolierte IDIS-Session (eigener Login).

        Args:
            amendments: Liste aller Amendments (bereits berechnet).
            run_date: Datum fuer IDIS Import Date Filter.
            stop_before_save: True = Felder ausfuellen, NICHT speichern.

        Returns:
            Gesamtanzahl erfolgreich angewendeter Amendments.
        """
        from idis_browser import IdisBrowser

        # Amendments nach Land gruppieren
        country_groups: dict[str, list[dict]] = {}
        for a in amendments:
            country = a.get("land", "UNKNOWN")
            country_groups.setdefault(country, []).append(a)

        countries = sorted(country_groups.keys())
        logger.info(
            "=== PARALLELVERARBEITUNG: %d Laender (%s), %d Amendments ===",
            len(countries), ", ".join(countries), len(amendments),
        )

        # Max parallele Browser-Contexts (konfigurierbar, default 4)
        parallel_cfg = self.cfg.get("parallel", {})
        max_parallel = parallel_cfg.get("max_countries", 4)
        semaphore = asyncio.Semaphore(max_parallel)

        # Workflow-Monitor: Step loggen
        self._log_workflow(
            "step",
            step_current="parallel-amendments",
            countries=countries,
            total_amendments=len(amendments),
        )

        async def _process_country(
            country: str, country_amendments: list[dict]
        ) -> int:
            """Verarbeitet alle Amendments eines Landes in eigenem Browser-Context."""
            async with semaphore:
                country_browser = IdisBrowser(self.config_path)
                country_browser._country_label = country
                # FIX: Eigener CDP-Port pro Land (kein Sharing)
                port = self.COUNTRY_PORTS.get(country, 9228)
                country_browser._conn._port = port
                country_browser._conn._cdp_url = f"http://127.0.0.1:{port}"
                try:
                    logger.info(
                        "[%s] Browser-Context starten (%d Amendments, Port %d)...",
                        country, len(country_amendments), port,
                    )

                    # Login (eigene Session pro Land)
                    await country_browser.login()
                    logger.info("[%s] Login erfolgreich", country)

                    # Result-Tabelle laden (Import Date Filter + Show Result)
                    row_count = await country_browser.show_filtered_results(
                        run_date, country=country
                    )
                    logger.info(
                        "[%s] Result-Tabelle: %d Zeilen", country, row_count
                    )

                    if row_count == 0:
                        logger.warning(
                            "[%s] Keine Orders in Tabelle — skip", country
                        )
                        return 0

                    # Amendments anwenden
                    applied = await country_browser.apply_amendments(
                        country_amendments, stop_before_save=stop_before_save
                    )
                    logger.info(
                        "[%s] Fertig: %d/%d Amendments %s",
                        country,
                        applied,
                        len(country_amendments),
                        "(nicht gespeichert)" if stop_before_save else "gespeichert",
                    )
                    return applied

                except Exception as e:
                    logger.error(
                        "[%s] Fehler bei Amendments: %s",
                        country, e, exc_info=True,
                    )
                    return 0
                finally:
                    # NUR Playwright-Verbindung trennen, NICHT _context.close()!
                    # context.close() invalidiert shared CDP Sessions anderer Laender.
                    try:
                        if hasattr(country_browser, "_pw") and country_browser._pw:
                            await country_browser._pw.stop()
                            country_browser._pw = None
                    except Exception as e:
                        logger.warning('Playwright stop: %s', e)

        # Alle Laender parallel ausfuehren
        results = await asyncio.gather(
            *[
                _process_country(c, country_groups[c])
                for c in countries
            ],
            return_exceptions=True,
        )

        # Ergebnisse aggregieren
        total = 0
        for i, result in enumerate(results):
            if isinstance(result, Exception):
                logger.error(
                    "[%s] Exception: %s", countries[i], result
                )
            elif isinstance(result, int):
                total += result

        logger.info(
            "=== PARALLELVERARBEITUNG ABGESCHLOSSEN: %d/%d Amendments ===",
            total, len(amendments),
        )
        return total

    # ------------------------------------------------------------------
    # Reprocessing
    # ------------------------------------------------------------------

    def run_reprocess(self, order_codes: list[str], run_date: date | None = None) -> dict:
        """Re-Run nur fuer bestimmte Order-Codes."""
        if run_date is None:
            run_date = date.today()

        start_time = datetime.now()
        result = {
            "date": str(run_date),
            "status": "pending",
            "mode": "reprocess",
            "order_codes": order_codes,
        }

        logger.info("=" * 60)
        logger.info("REPROCESS START: %d Orders", len(order_codes))
        logger.info("=" * 60)

        try:
            master = MasterData(self.config_path)
            valid_keys, still_missing = master.validate_orders(order_codes)
            valid_keys_set = set(valid_keys)

            if still_missing:
                logger.warning(
                    "Immer noch fehlende Masterdaten: %s",
                    ", ".join(still_missing),
                )
                result["still_missing"] = still_missing

            if not valid_keys:
                logger.error("Keine validen Orders fuer Reprocessing.")
                result["status"] = "error"
                result["error"] = "Keine validen Orders"
                return result

            exports_dir = Path(self.cfg["paths"]["exports_dir"])
            post_export = self._find_latest_export(exports_dir, run_date, "post")

            if not post_export:
                logger.error("Kein Post-Export gefunden fuer %s", run_date)
                result["status"] = "error"
                result["error"] = "Post-Export nicht gefunden"
                return result

            from idis_browser import IdisBrowser
            browser = IdisBrowser(self.config_path)
            all_rows = browser._parse_csv(post_export)

            filtered_rows = [
                r for r in all_rows
                if str(r.get("aros_key", "")) in valid_keys_set
            ]

            logger.info("Reprocessing: %d Zeilen fuer %d Orders", len(filtered_rows), len(valid_keys))

            gen = PicklistGenerator(master, self.config_path)
            generated = gen.generate(filtered_rows, run_date)

            end_time = datetime.now()
            report = DailyReport(self.config_path)
            plausibility_ok, report_path = report.generate_report(
                run_date=run_date,
                start_time=start_time,
                end_time=end_time,
                export_rows=filtered_rows,
                generated_lists=generated,
                missing_keys=still_missing,
            )

            if generated:
                if PRINTER_AVAILABLE:
                    printer = Printer(self.config_path)
                    print_result = printer.print_all(generated)
                    result["print"] = print_result
                else:
                    logger.warning("REPROCESS: Druck uebersprungen (Printer-Modul nicht verfuegbar)")
                    result["print"] = {"skipped": True, "reason": "printer_unavailable"}
            else:
                result["print"] = {"skipped": True, "reason": "no_picklists"}

            result["generated"] = len(generated)
            result["status"] = "completed"

        except Exception as e:
            logger.error("REPROCESS FEHLER: %s", e, exc_info=True)
            result["status"] = "error"
            result["error"] = str(e)
            result["traceback"] = traceback.format_exc()

        result["duration_seconds"] = (datetime.now() - start_time).total_seconds()
        self._send_report(result, run_date)

        # End-Email mit Ergebnis senden
        try:
            send_end_email(result, test_mode=False)
        except Exception as e:
            logger.warning("End-Email fehlgeschlagen (unkritisch): %s", e)

        return result

    # ------------------------------------------------------------------
    # Hilfsfunktionen
    # ------------------------------------------------------------------

    @staticmethod
    def _find_latest_export(exports_dir: Path, run_date: date, suffix: str) -> str | None:
        """Findet den neuesten Export fuer ein Datum."""
        pattern = f"IDIS_EXPORT_{run_date.strftime('%Y-%m-%d')}_{suffix}.csv"
        path = exports_dir / pattern
        if path.exists():
            return str(path)
        return None


# ------------------------------------------------------------------
# CLI-Interface
# ------------------------------------------------------------------

def main():
    """Kommandozeilen-Interface fuer den Orchestrator."""
    os.makedirs("logs", exist_ok=True)

    logging.basicConfig(
        level=logging.INFO,
        format="%(asctime)s [%(levelname)s] %(name)s: %(message)s",
        handlers=[
            logging.StreamHandler(sys.stdout),
            logging.FileHandler("logs/pipeline.log", encoding="utf-8"),
        ],
    )

    import argparse

    parser = argparse.ArgumentParser(description="Nacke Logistik Pipeline")
    parser.add_argument(
        "--date",
        type=str,
        default=None,
        help="Datum im Format YYYY-MM-DD (default: heute)",
    )
    parser.add_argument(
        "--dry-run",
        action="store_true",
        help="Testlauf: Export + Berechnung + Picklisten, "
        "KEINE Buchung in IDIS, KEIN Druck",
    )
    parser.add_argument(
        "--stop-before-save",
        action="store_true",
        help="Schritte 1-4 ausfuehren, Amendments in IDIS-Felder eintragen "
        "aber NICHT speichern. Pipeline stoppt nach Schritt 4.",
    )
    parser.add_argument(
        "--reprocess",
        nargs="+",
        type=str,
        default=None,
        help="AROS-Keys fuer Nachverarbeitung",
    )
    parser.add_argument(
        "--config",
        type=str,
        default="config.json",
        help="Pfad zur config.json",
    )

    args = parser.parse_args()

    run_date = date.today()
    if args.date:
        run_date = date.fromisoformat(args.date)

    orch = Orchestrator(args.config)

    if args.reprocess:
        result = orch.run_reprocess(args.reprocess, run_date)
    else:
        result = orch.run_full_pipeline(
            run_date,
            dry_run=args.dry_run,
            stop_before_save=args.stop_before_save,
        )

    # Ergebnis ausgeben
    print(json.dumps(result, indent=2, default=str))

    # FIX: Exit-Code 0 bei "no_orders" (kein Fehler, nur keine Daten)
    if result.get("status") == "error":
        sys.exit(1)
    sys.exit(0)


if __name__ == "__main__":
    main()

