/**
 * Potenzielle Kontakte auf LinkedIn suchen.
 * 
 * Nutzt die LinkedIn-Suche mit:
 * - Keywords (z.B. 'CEO', 'CTO')
 * - Geo-Filter (DACH, Nordics, etc.)
 * - 2nd-Degree Filter (nur Kontakte 2. Grades)
 * 
 * TODO: Geo-Filter Selektor nach LinkedIn UI-Update pruefen!
 */
export async function searchTargets(session, keywords, targetGeo) {
  const { page } = session;
  const targets = [];

  for (const keyword of keywords) {
    // LinkedIn-Suche aufrufen
    const searchUrl = `https://www.linkedin.com/search/results/people/?keywords=${encodeURIComponent(keyword)}&network=%5B%22S%22%5D`;
    await page.goto(searchUrl, { waitUntil: 'domcontentloaded' });

    // Humanisierte Wartezeit (2-4 Sekunden, Gauss-verteilt)
    await page.waitForTimeout(2000 + Math.random() * 2000);

    // Ergebnis-Cards sammeln
    const cards = await page.$$('.entity-result__item');

    for (const card of cards.slice(0, 10)) {
      const name = await card.$eval('.entity-result__title-text a', el => el.textContent.trim()).catch(() => null);
      const title = await card.$eval('.entity-result__primary-subtitle', el => el.textContent.trim()).catch(() => null);
      const profileUrl = await card.$eval('.entity-result__title-text a', el => el.href).catch(() => null);

      if (name && profileUrl) {
        targets.push({ name, title, profileUrl, keyword });
      }
    }

    console.log(`Keyword '${keyword}': ${cards.length} Ergebnisse gefunden`);
  }

  return targets;
}

