/**
 * Alle Aktionen einer Session in Supabase loggen.
 * 
 * Jede Aktion wird als einzelne Zeile gespeichert:
 * - account_id: welcher Account
 * - action_type: 'connect', 'browse', 'search'
 * - target_name: Name des Kontakts
 * - created_at: Zeitstempel (automatisch von Supabase)
 * 
 * Diese Daten nutzt der Account Guard fuer Rate Limit Checks.
 */
export async function logActivity(sb, accountId, results) {
  if (!results || results.length === 0) return;

  // Alle Ergebnisse in Activity-Records umwandeln
  const records = results.map(r => ({
    account_id: accountId,
    action_type: r.action || 'unknown',
    target_name: r.name || null,
    status: r.status,
    metadata: JSON.stringify(r)
  }));

  // Batch-Insert in Supabase
  const { data, error } = await sb
    .from('linkedin_activity')
    .insert(records);

  if (error) {
    console.error(`Activity-Log Fehler: ${error.message}`);
    throw error;
  }

  console.log(`${records.length} Aktionen geloggt fuer Account ${accountId}`);
  return data;
}
